#include <stdio.h>
#include <string.h>
#include <stdlib.h>

char* removeKdigits(const char* num, int k) {
    int len = strlen(num);
    char* stack = (char*)malloc((len + 1) * sizeof(char));
    int top = -1;
    for (int i = 0; i < len; ++i) {
        char c = num[i];
        while (k > 0 && top >= 0 && stack[top] > c) {
            --top;
            --k;
        }
        stack[++top] = c;
    }
    while (k > 0 && top >= 0) {
        --top;
        --k;
    }
    int start = 0;
    while (start <= top && stack[start] == '0') ++start;
    int resLen = top - start + 1;
    char* res = (char*)malloc((resLen + 1) * sizeof(char));
    if (resLen > 0) {
        memcpy(res, stack + start, resLen);
    }
    res[resLen] = '\0';
    free(stack);
    return res;
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int n, k;
        scanf("%d %d", &n, &k);
        char num[100005];
        scanf("%s", num);
        char* ans = removeKdigits(num, k);
        if (ans[0] == '\0')
            printf("0");
        else
            printf("%s", ans);
        if (T) printf("\n");
        free(ans);
    }
    return 0;
}

