#include <bits/stdc++.h>
using namespace std;

string removeKdigits(const string& num, int k) {
    deque<char> dq;
    for (char c : num) {
        while (k > 0 && !dq.empty() && dq.back() > c) {
            dq.pop_back();
            --k;
        }
        dq.push_back(c);
    }
    while (k-- > 0 && !dq.empty()) dq.pop_back();
    while (!dq.empty() && dq.front() == '0') dq.pop_front();
    if (dq.empty()) return "0";
    return string(dq.begin(), dq.end());
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T;
    if (!(cin >> T)) return 0;
    while (T--) {
        int n, k;
        cin >> n >> k;
        string num;
        cin >> num;
        cout << removeKdigits(num, k);
        if (T) cout << '\n';
    }
    return 0;
}

